const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n, s;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        s = input;
        let count = 0;
        for (let i = 0; i < n - 2; i++) {
            if (s[i] === s[i + 1] && s[i] === s[i + 2]) {
                count++;
            }
        }
        console.log(count);
        rl.close();
    }
});
